import { NextRequest, NextResponse } from 'next/server';
import { ApiResponse, RacquetWithReviews } from '@/lib/types';
import { RacquetService } from '@/lib/services/racquet-service';

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const racquetService = new RacquetService();
    const racquet = await racquetService.getRacquetById(id);

    if (!racquet) {
      return NextResponse.json(
        { error: 'Racquet not found' },
        { status: 404 }
      );
    }

    const response: ApiResponse<RacquetWithReviews> = {
      data: racquet,
    };

    return NextResponse.json(response);
  } catch (error) {
    console.error('Error fetching racquet:', error);
    return NextResponse.json(
      { error: 'Failed to fetch racquet' },
      { status: 500 }
    );
  }
}

