import { z } from 'zod';

export const RacquetFiltersSchema = z.object({
  brand: z.string().optional().transform(val => val?.split(',') || undefined),
  weight_min: z.string().optional().transform(val => val ? Number(val) : undefined),
  weight_max: z.string().optional().transform(val => val ? Number(val) : undefined),
  head_size_min: z.string().optional().transform(val => val ? Number(val) : undefined),
  head_size_max: z.string().optional().transform(val => val ? Number(val) : undefined),
  power_min: z.string().optional().transform(val => val ? Number(val) : undefined),
  power_max: z.string().optional().transform(val => val ? Number(val) : undefined),
  control_min: z.string().optional().transform(val => val ? Number(val) : undefined),
  control_max: z.string().optional().transform(val => val ? Number(val) : undefined),
  comfort_min: z.string().optional().transform(val => val ? Number(val) : undefined),
  comfort_max: z.string().optional().transform(val => val ? Number(val) : undefined),
  maneuverability_min: z.string().optional().transform(val => val ? Number(val) : undefined),
  maneuverability_max: z.string().optional().transform(val => val ? Number(val) : undefined),
  stability_min: z.string().optional().transform(val => val ? Number(val) : undefined),
  stability_max: z.string().optional().transform(val => val ? Number(val) : undefined),
  search: z.string().optional(),
  limit: z.string().optional().transform(val => val ? Number(val) : 50),
  offset: z.string().optional().transform(val => val ? Number(val) : 0),
}).refine(
  data => {
    if (data.weight_min && data.weight_max) {
      return data.weight_min <= data.weight_max;
    }
    return true;
  },
  { message: 'weight_min must be less than or equal to weight_max' }
).refine(
  data => {
    if (data.head_size_min && data.head_size_max) {
      return data.head_size_min <= data.head_size_max;
    }
    return true;
  },
  { message: 'head_size_min must be less than or equal to head_size_max' }
).refine(
  data => {
    if (data.power_min && data.power_max) {
      return data.power_min <= data.power_max;
    }
    return true;
  },
  { message: 'power_min must be less than or equal to power_max' }
).refine(
  data => {
    if (data.control_min && data.control_max) {
      return data.control_min <= data.control_max;
    }
    return true;
  },
  { message: 'control_min must be less than or equal to control_max' }
).refine(
  data => {
    if (data.limit && (data.limit < 1 || data.limit > 100)) {
      return false;
    }
    return true;
  },
  { message: 'limit must be between 1 and 100' }
).refine(
  data => {
    if (data.offset && data.offset < 0) {
      return false;
    }
    return true;
  },
  { message: 'offset must be 0 or greater' }
);

export const RacquetIdSchema = z.object({
  id: z.string().min(1, 'Racquet ID is required'),
});

export const ApiErrorSchema = z.object({
  error: z.string(),
  message: z.string().optional(),
  code: z.string().optional(),
  details: z.any().optional(),
});

export class ValidationError extends Error {
  constructor(
    message: string,
    public issues: z.ZodIssue[]
  ) {
    super(message);
    this.name = 'ValidationError';
  }
}

export function validateSearchParams(searchParams: URLSearchParams) {
  const params = Object.fromEntries(searchParams.entries());
  const result = RacquetFiltersSchema.safeParse(params);

  if (!result.success) {
    throw new ValidationError('Invalid query parameters', result.error.issues);
  }

  return result.data;
}

export function validateRacquetId(id: string) {
  const result = RacquetIdSchema.safeParse({ id });

  if (!result.success) {
    throw new ValidationError('Invalid racquet ID', result.error.issues);
  }

  return result.data.id;
}

