import {
  validateSearchParams,
  validateRacquetId,
  ValidationError,
  RacquetFiltersSchema,
} from '@/lib/validation';

describe('Validation', () => {
  describe('validateSearchParams', () => {
    it('should parse valid search parameters', () => {
      const searchParams = new URLSearchParams({
        brand: 'Wilson,Babolat',
        weight_min: '10',
        weight_max: '12',
        power_min: '7',
        power_max: '9',
        search: 'Pro Staff',
        limit: '25',
        offset: '10',
      });

      const result = validateSearchParams(searchParams);

      expect(result).toEqual({
        brand: ['Wilson', 'Babolat'],
        weight_min: 10,
        weight_max: 12,
        power_min: 7,
        power_max: 9,
        search: 'Pro Staff',
        limit: 25,
        offset: 10,
        head_size_min: undefined,
        head_size_max: undefined,
        control_min: undefined,
        control_max: undefined,
        comfort_min: undefined,
        comfort_max: undefined,
        maneuverability_min: undefined,
        maneuverability_max: undefined,
        stability_min: undefined,
        stability_max: undefined,
      });
    });

    it('should use default values for missing parameters', () => {
      const searchParams = new URLSearchParams();
      const result = validateSearchParams(searchParams);

      expect(result.limit).toBe(50);
      expect(result.offset).toBe(0);
      expect(result.brand).toBeUndefined();
      expect(result.search).toBeUndefined();
    });

    it('should throw ValidationError for invalid weight range', () => {
      const searchParams = new URLSearchParams({
        weight_min: '15',
        weight_max: '10',
      });

      expect(() => validateSearchParams(searchParams)).toThrow(ValidationError);

      try {
        validateSearchParams(searchParams);
      } catch (error) {
        expect(error).toBeInstanceOf(ValidationError);
        expect((error as ValidationError).issues[0].message).toBe(
          'weight_min must be less than or equal to weight_max'
        );
      }
    });

    it('should throw ValidationError for invalid limit', () => {
      const searchParams = new URLSearchParams({
        limit: '150',
      });

      expect(() => validateSearchParams(searchParams)).toThrow(ValidationError);

      try {
        validateSearchParams(searchParams);
      } catch (error) {
        expect(error).toBeInstanceOf(ValidationError);
        expect((error as ValidationError).issues[0].message).toBe(
          'limit must be between 1 and 100'
        );
      }
    });

    it('should throw ValidationError for negative offset', () => {
      const searchParams = new URLSearchParams({
        offset: '-5',
      });

      expect(() => validateSearchParams(searchParams)).toThrow(ValidationError);

      try {
        validateSearchParams(searchParams);
      } catch (error) {
        expect(error).toBeInstanceOf(ValidationError);
        expect((error as ValidationError).issues[0].message).toBe(
          'offset must be 0 or greater'
        );
      }
    });
  });

  describe('validateRacquetId', () => {
    it('should validate valid racquet ID', () => {
      const result = validateRacquetId('123');
      expect(result).toBe('123');
    });

    it('should validate alphanumeric racquet ID', () => {
      const result = validateRacquetId('ABC123');
      expect(result).toBe('ABC123');
    });

    it('should throw ValidationError for empty ID', () => {
      expect(() => validateRacquetId('')).toThrow(ValidationError);

      try {
        validateRacquetId('');
      } catch (error) {
        expect(error).toBeInstanceOf(ValidationError);
        expect((error as ValidationError).issues[0].message).toBe(
          'Racquet ID is required'
        );
      }
    });
  });

  describe('RacquetFiltersSchema', () => {
    it('should handle all filter ranges correctly', () => {
      const params = {
        power_min: '7',
        power_max: '9',
        control_min: '8',
        control_max: '10',
        comfort_min: '6',
        comfort_max: '8',
        maneuverability_min: '7',
        maneuverability_max: '9',
        stability_min: '8',
        stability_max: '10',
      };

      const result = RacquetFiltersSchema.parse(params);

      expect(result.power_min).toBe(7);
      expect(result.power_max).toBe(9);
      expect(result.control_min).toBe(8);
      expect(result.control_max).toBe(10);
      expect(result.comfort_min).toBe(6);
      expect(result.comfort_max).toBe(8);
      expect(result.maneuverability_min).toBe(7);
      expect(result.maneuverability_max).toBe(9);
      expect(result.stability_min).toBe(8);
      expect(result.stability_max).toBe(10);
    });

    it('should validate all range constraints', () => {
      const invalidRanges = [
        { power_min: '10', power_max: '5' },
        { control_min: '10', control_max: '5' },
        { head_size_min: '110', head_size_max: '90' },
      ];

      invalidRanges.forEach((params) => {
        expect(() => RacquetFiltersSchema.parse(params)).toThrow();
      });
    });
  });
});

